        , width : 900
        , height : 740
    };

    // var data = {
    //     args: args
    // };

    var resultAdd = await $c.win.openPopup("/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_18p.xml", opts, args);

    if ( resultAdd != null ) {
        scwin.f_AddRow2(resultAdd);
    }
};


