scwin.f_checkLunion = async function() {
    var row = ds_retrieveResult2.getRowCount();

    for (i = 0; i < row; i++) {
        var lunion = ds_retrieveResult2.getCellData(i, "lunionOrgCd");
        if ( lunion == "" ) {
            await $c.gus.cfAlertMsg("하역투입반원등록 작업을 먼저 실행하십시오.");
            ds_retrieveResult2.removeAll();
            return false;
        }
    }
    return true;
};


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }

    scwin.make_mandatory_related_orderNo_from_condition();    
};



