    totalRows.setValue(rowcnt);

    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg("해당하는 하역노임실적이 없습니다.");
        return;
    }

    // 타창고 작업장인 경우에만  퇴직충당금 지급여부 보여줌. 
    if (scwin.otherWarehouseYn =='W') { 
